import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface PasswordHealthData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    overallSecurityScore: number;
    weakPasswords: {
      count: number;
      examples: string[];
    };
    reusedPasswords: {
      count: number;
      examples: string[];
    };
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const { data, meta } = response as PasswordHealthData;
  const { overallSecurityScore, weakPasswords, reusedPasswords } = data.data;
  const themeColor = meta.primaryColor;
  const secondaryColor = meta.accentColor;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 400,
        bgcolor: 'rgba(50, 50, 50, 0.5)',
        backdropFilter: 'blur(8px)',
        borderRadius: 2,
        boxShadow: '0 4px 30px rgba(0, 0, 0, 0.1)',
        border: '1px solid rgba(255, 255, 255, 0.3)',
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: themeColor, mb: 1 }}>
              SecurePass - Password Health
            </Typography>
            <Typography variant="body2" sx={{ color: '#fff' }}>
              Overall Security Score:
            </Typography>
            <Typography variant="h4" sx={{ color: themeColor, fontWeight: 700 }}>
              {overallSecurityScore}%
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: 'rgba(255, 255, 255, 0.2)' }} />

          <Box>
            <Stack direction="row" justifyContent="space-between" alignItems="center">
              <Typography variant="body2" sx={{ color: '#fff' }}>
                Weak Passwords
              </Typography>
              <Info sx={{ fontSize: 16, color: secondaryColor }} />
            </Stack>
            <Stack direction="row" spacing={0.5} mt={0.5}>
              {weakPasswords.examples.slice(0, 3).map((password, index) => (
                <Chip
                  key={index}
                  label={password}
                  sx={{
                    fontSize: '11px',
                    bgcolor: secondaryColor,
                    color: '#fff',
                    px: 1,
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Divider sx={{ bgcolor: 'rgba(255, 255, 255, 0.2)' }} />

          <Box>
            <Stack direction="row" justifyContent="space-between" alignItems="center">
              <Typography variant="body2" sx={{ color: '#fff' }}>
                Reused Passwords
              </Typography>
              <Info sx={{ fontSize: 16, color: secondaryColor }} />
            </Stack>
            <Stack direction="row" spacing={0.5} mt={0.5}>
              {reusedPasswords.examples.slice(0, 3).map((password, index) => (
                <Chip
                  key={index}
                  label={password}
                  sx={{
                    fontSize: '11px',
                    bgcolor: secondaryColor,
                    color: '#fff',
                    px: 1,
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
